  ?tournament rdfs:label "US Men's Clay Court Championships"@en;
             wdt:P31 wd:Q12742913;
             wdt:P585 ?eventDate.
  FILTER (year(?eventDate) = 2019).
  ?player p:P1246 ?statement.
  ?statement ps:P1246 ?tournament.
